			&lt;td&gt;Ustilago avenae&lt;/td&gt;
			&lt;td&gt;Loose smut of oat&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;ul&gt;
	&lt;li&gt;गेहूं की ढीली गंध कवक उस्तिलागो त्रिती के कारण होती है।&lt;/li&gt;
	&lt;li&gt;इससे संक्रमित एक पौधा आमतौर पर स्वस्थ पौधों की तुलना में पहले सिर का उत्पादन करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;जीव&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&lt;strong&gt;रोगज़नक़&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&lt;strong&gt;पादप रोग&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;कवक&lt;/td&gt;
			&lt;td&gt;उस्तिलागो त्रिती&lt;/td&gt;
			&lt;td&gt;गेहूँ की ढीली ढेरी&lt;/td&gt;
			&lt;td&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
