&lt;p style=&quot;&quot;&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;voltmeter&lt;/span&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;A Voltmeter&lt;/span&gt;&amp;nbsp;is an instrument used to&amp;nbsp;measure&amp;nbsp;the potential difference&amp;nbsp;in a circuit.&lt;/li&gt;
	&lt;li&gt;A&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;voltmeter i&lt;/span&gt;s always connected in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;parallel&lt;/span&gt;&amp;nbsp;in the circuit&amp;nbsp;to&amp;nbsp;measure&amp;nbsp;the&amp;nbsp;potential difference between two points.&lt;/li&gt;
	&lt;li&gt;Unit of Potential Difference&amp;nbsp;-&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Volt&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;A&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;galvanometer&lt;/span&gt;&amp;nbsp;can be converted into a voltmeter by connecting a large resistance in&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;series&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Voltmeter was invented by&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Hans Orested&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

