&lt;/table&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्&amp;zwj;तर है &lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rarr; वोल्टमीटर&lt;/span&gt;&lt;/u&gt; ।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वोल्टमीटर&lt;/span&gt; एक उपकरण है जिसका उपयोग परिपथ&amp;nbsp;में विभव&amp;nbsp;अंतर को मापने के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;दो बिंदुओं के बीच &lt;span style=&quot;&quot;&gt;विभव&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;अंतर को मापने के लिए &lt;span style=&quot;font-weight: 700;&quot;&gt;वोल्टमीटर&lt;/span&gt; हमेशा परिपथ&amp;nbsp;में &lt;span style=&quot;font-weight: 700;&quot;&gt;समानांतर&lt;/span&gt; में जुड़ा होता है।&lt;/li&gt;
	&lt;li&gt;विभवान्तर की इकाई - &lt;span style=&quot;font-weight: 700;&quot;&gt;वोल्ट&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;श्रेणी &lt;/strong&gt;में एक बड़े प्रतिरोध को जोड़कर एक &lt;strong&gt;&lt;span style=&quot;&quot;&gt;धारामापी&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;को वोल्टमीटर में परिवर्तित किया जा सकता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;वोल्टमीटर&amp;nbsp;&lt;/span&gt;का आविष्कार &lt;span style=&quot;font-weight: 700;&quot;&gt;हैंस ओरेस्टेड&lt;/span&gt; ने किया था &lt;span style=&quot;font-weight: 700;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot; width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;उपकरण का नाम&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;निम्न के लिए कार्य/उपयुक्त&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बैरोमीटर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वायुमंडलीय दबाव को मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;धारामापी&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;छोटे विद्युत धारा को मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;एम्मिटर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;विद्युत प्रवाह की ताकत को मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center; &quot;&gt;पाइरोमीटर&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बहुत उच्च तापमान मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कैलोरीमीटर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ऊष्मा की मात्रा को मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;पालीग्राफ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center; &quot;&gt;परिवर्तन रिकॉर्ड करने, साथ ही साथ शारीरिक प्रक्रियाओं जैसे दिल की धड़कन, रक्तचाप और श्वसन में भी लाई डिटेक्टर के रूप में उपयोग किया जाता है&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center; &quot;&gt;इलेक्ट्रोकार्डियोग्राफ (ECG)&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;दिल की गतिविधियों को मापना।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center; &quot;&gt;डायनेमो&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;यांत्रिक ऊर्जा को विद्युत ऊर्जा में परिवर्तित करता है।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;पेरिस्कोप&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;समुद्र तल से ऊपर की वस्तुओं को देखने के लिए उपयोग किया जाता है।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;इलेक्ट्रोएन्सेफलोग्राफ (ईईजी)&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मस्तिष्क में विद्युतीय गतिविधियों को मापता है।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;The correct answer is&amp;nbsp;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;Lysosome&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​Lysosome:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;Lysosomes are an important cell organelle found within&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;eukaryotic animal cells&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;Due to their peculiar function, they are also known as the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;ldquo;suicide bags&amp;rdquo; of the cell&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;Lysosomes work as the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;waste-discarding structures of the cell by processing undesirable materials and degrading them&lt;/span&gt;, both from the exterior of the cell and waste constituents inside the cell.&lt;/li&gt;
		&lt;li&gt;But sometimes, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;digestive enzymes may end up damaging the lysosomes themselves&lt;/span&gt;, and this can cause the cell to die.&lt;/li&gt;
		&lt;li&gt;This is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;termed autolysis&lt;/span&gt;, where &lt;strong&gt;&amp;ldquo;auto&amp;rdquo; means &amp;ldquo;self&amp;rdquo; and &amp;ldquo;lysis&amp;rdquo; means &amp;ldquo;the disintegration of the cell by the destruction of its cell membrane&amp;ldquo;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Peroxisomes:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;It is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;microbody&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;In-plant it helps in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;photorespiration&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;In animals concerned with&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;peroxide metabolism.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Glyoxysomes&lt;/span&gt;: These are the &lt;strong&gt;special type of peroxisomes found in plants &amp;amp; some fungi.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Polysome:&lt;/strong&gt; Many &lt;strong&gt;ribosomes may associate with a single mRNA&lt;/strong&gt; to form &lt;strong&gt;multiple copies of a polypeptide simultaneously&lt;/strong&gt;.
	&lt;ul&gt;
		&lt;li&gt;Such strings of ribosomes are termed as&amp;nbsp;&lt;strong&gt;Polysome&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&lt;u&gt;लाइसोसोम&lt;/u&gt;&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&lt;strong&gt;लाइसोसोम&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;लाइसोसोम&lt;strong&gt;&amp;nbsp;यूकैरियोटिक जीव&amp;nbsp;कोशिकाओं &lt;/strong&gt;के भीतर पाए जाने वाले एक महत्वपूर्ण कोशिकांग हैं।&lt;/li&gt;
		&lt;li&gt;उनके विशिष्ट कार्य के कारण, उन्हें &lt;strong&gt;कोशिका की&amp;nbsp;&amp;quot;आत्मघाती थैली&amp;quot; &lt;/strong&gt;के रूप में भी जाना जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;लाइसोसोम&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;कोशिका&amp;nbsp;के बाहरी हिस्से और कोशिका के अंदर&amp;nbsp;दोंनों से&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); font-weight: bolder;&quot;&gt;अवांछित सामग्रियों&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;को संसाधित करके&lt;/strong&gt; और &lt;strong&gt;अपघटित करके कोशिका के अपशिष्ट-निस्तारण संरचनाओं &lt;/strong&gt;के रूप में काम करते हैं।&lt;/li&gt;
		&lt;li&gt;लेकिन कभी-कभी, &lt;strong&gt;पाचक एंजाइम स्वयं &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;लाइसोसोम&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;को नुकसान पहुंचा सकते हैं,&lt;/strong&gt; और इससे कोशिका मर सकती है।&lt;/li&gt;
		&lt;li&gt;इसे &lt;strong&gt;ऑटोलिसिस (स्वलयन) कहा जाता&lt;/strong&gt; है, जहां&lt;strong&gt; &amp;quot;ऑटो&amp;quot; का अर्थ है &amp;quot;स्वयं&amp;quot; और &amp;quot;लिसिस&amp;quot; का अर्थ है &amp;quot;कोशिका झिल्ली के खंडन&lt;/strong&gt;&lt;strong&gt; से कोशिका का विघटन&amp;quot;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;परऑक्सीसोम&amp;nbsp;&lt;/span&gt;(सुक्ष्मकाय):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;यह एक &lt;strong&gt;सुक्ष्मकाय&lt;/strong&gt;&amp;nbsp;होती है।&lt;/li&gt;
		&lt;li&gt;पौधे में यह &lt;strong&gt;प्रकाश श्वसन&lt;/strong&gt; में सहायता करता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;पराॅक्साइड चयापचय&lt;/strong&gt; से संबंधित जंतुओं में होता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ग्लाइऑक्सिसोम: &lt;/strong&gt;ये &lt;strong&gt;पौधों और कुछ कवक में पाए जाने वाले विशेष प्रकार के &lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;परऑक्सीसोम&amp;nbsp;&lt;/span&gt;हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पॉलीसोम (बहुसूत्रक):&lt;/strong&gt; कई &lt;strong&gt;राइबोसोम एक साथ एक पॉलीपेप्टाइड की कई प्रतियाँ बनाने के लिए एक ही mRNA के साथ जुड़ सकते हैं।&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;राइबोसोम के ऐसे तंत्र&amp;nbsp;को &lt;strong&gt;पॉलीसोम&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Peacock.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;Peacock has a&lt;strong&gt; four-chambered&lt;/strong&gt; heart.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Peacock &lt;/span&gt;is the &lt;strong&gt;national bird&lt;/strong&gt; of&lt;strong&gt; India&lt;/strong&gt;&amp;nbsp;and its &lt;strong&gt;scientific name&lt;/strong&gt; is&amp;nbsp;&lt;em&gt;Pavo cristatus.&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Taxonomy of Peacock:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Kingdom&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Animalia&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Phylum&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Chordata&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subphylum&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Vertebrata&amp;nbsp;&amp;nbsp;&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Superclass&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Tetrapoda&amp;nbsp;&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Class&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Aves&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;&amp;nbsp;&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Order&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Galliformes&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Family&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Phasianidae&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Genus&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;Pavo&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Species&lt;/span&gt;:&lt;span style=&quot;white-space: pre;&quot;&gt; &lt;/span&gt;cristatus&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The &lt;strong&gt;frog&lt;/strong&gt; belongs to the class &lt;strong&gt;Amphibia&lt;/strong&gt; and&amp;nbsp;has a characteristic&lt;strong&gt;&amp;nbsp;three-chambered heart&lt;/strong&gt; with &lt;strong&gt;2 auricles and 1 ventricle.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Fishes &lt;/strong&gt;have a&amp;nbsp;&lt;strong&gt;two-chambered heart.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Sea horses &lt;/strong&gt;have a&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;two-chambered heart&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;मोर&lt;/strong&gt;&lt;/u&gt; है।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मोर का हृदय &lt;strong&gt;चार कक्षों वाला&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मोर&lt;/strong&gt; &lt;strong&gt;भारत&lt;/strong&gt; का &lt;strong&gt;राष्ट्रीय पक्षी&lt;/strong&gt; है और इसका &lt;strong&gt;वैज्ञानिक नाम पावो क्रिस्टेटस&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मोर का वर्गीकरण:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;किंगडम: &lt;/strong&gt;जन्तु&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;फाइलम:&lt;/strong&gt; कॉर्डेटा&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;सबफाइलम&lt;/span&gt;&lt;strong&gt;:&lt;/strong&gt; कशेरुका&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;महावर्ग:&lt;/strong&gt; टेट्रापोडा&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;वर्ग&lt;/span&gt;&lt;strong&gt;:&lt;/strong&gt; एवेस&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;क्रम:&lt;/strong&gt; गैलीफोर्मेस&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;परिवार:&lt;/strong&gt; फासियानिडे&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;जाति&lt;/strong&gt;&lt;strong&gt;:&lt;/strong&gt; पावो&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;प्रजाति:&lt;/strong&gt; क्रिस्टेटस&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मेंढक उभयचर&lt;/strong&gt; वर्ग से संबंधित है और इसमें &lt;strong&gt;2 &lt;span style=&quot;color: rgb(102, 102, 102);   &quot;&gt;अलिंद&lt;/span&gt;&lt;strong&gt; &lt;/strong&gt;और 1 निलय&lt;/strong&gt;&amp;nbsp;के साथ &lt;strong&gt;तीन-कक्षीय हृदय&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मछलियों&lt;/strong&gt; में &lt;strong&gt;दो कक्षीय हृदय&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(102, 102, 102); &quot;&gt;अश्&amp;zwj;वमीन&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;(&lt;span style=&quot;font-weight: 700; &quot;&gt;Sea horses)&amp;nbsp;&lt;/span&gt;का &lt;strong&gt;ह्रदय&amp;nbsp;दो-कक्षीय&lt;/strong&gt; होता है। ​&lt;/li&gt;
&lt;/ul&gt;

&lt;div style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/u&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;Instantaneous velocity in two dimensions is written as&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{v} = v_x\widehat{i}+v_y\widehat{j}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;It is given that &lt;strong&gt;the instantaneous speed is constant which means the magnitude of instantaneous velocity is constant,&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;but the directions are changing within the plane and thus &lt;strong&gt;it is an accelerated motion.&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = \frac{d\vec{v}}{dt}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&amp;there4;&amp;nbsp;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = \frac{dv_x}{dt}\widehat{i}+\frac{dv_y}{dt}\widehat{j}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&amp;there4;&amp;nbsp;&lt;strong&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = a_x\widehat{i}+a_y\widehat{j}\)&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;strong&gt;Hence, the acceleration is necessarily in the plane of motion.&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;strong&gt;&amp;there4; Option 3) is correct.&lt;/strong&gt;&lt;/div&gt;<br><br>&lt;div style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;व्याख्या:&lt;/strong&gt;&lt;/u&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;दो विमाओं में तात्क्षणिक वेग को इस प्रकार लिखा जाता है,&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{v} = v_x\widehat{i}+v_y\widehat{j}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;यह दिया गया है कि&lt;strong&gt; &lt;/strong&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;तात्क्षणिक&lt;/span&gt; &lt;span style=&quot;&quot;&gt;चाल&lt;/span&gt; स्थिर है, जिसका अर्थ है कि &lt;span style=&quot;&quot;&gt;तात्क्षणिक&lt;/span&gt; वेग का परिमाण स्थिर है,&lt;/strong&gt;&lt;br /&gt;
लेकिन तल के भीतर दिशाएं बदल रही हैं और &lt;strong&gt;इस प्रकार यह एक त्वरित गति है।&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = \frac{d\vec{v}}{dt}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&amp;there4;&amp;nbsp;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = \frac{dv_x}{dt}\widehat{i}+\frac{dv_y}{dt}\widehat{j}\)&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&amp;there4;&amp;nbsp;&lt;strong&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\vec{a} = a_x\widehat{i}+a_y\widehat{j}\)&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;strong&gt;इसलिए, गति के तल में त्वरण आवश्यक है।&lt;/strong&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;&lt;strong&gt;&amp;there4; विकल्प (3) सही है।&amp;nbsp;&lt;/strong&gt;&lt;/div&gt;

&lt;p&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;​night blindness.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Night blindness is a type of vision impairment also known as nyctalopia.&lt;/li&gt;
	&lt;li&gt;People with night blindness experience poor vision at night or in dimly lit environments.&lt;/li&gt;
	&lt;li&gt;Although the term &amp;ldquo;night blindness&amp;rdquo; implies that you can&amp;#39;t see at night, this isn&amp;#39;t the case.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Deficiency of Vitamin C&lt;/span&gt;&amp;nbsp;(ascorbic acid)&amp;nbsp;causes&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Scurvy&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Deficiency of Vitamin D&lt;/span&gt;&amp;nbsp;(calciferol) causes&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Rickets&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Deficiency of Vitamin B7&lt;/span&gt;&amp;nbsp;(Biotin) causes&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;hair fall&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;रतौंधी&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;रतौंधी एक प्रकार की दृष्टि हानि है जिसे निक्टालोपिया भी कहा जाता है।&lt;/li&gt;
	&lt;li&gt;रतौंधी वाले लोगों को रात में या कम रोशनी वाले वातावरण में खराब दृष्टि का अनुभव होता है।&lt;/li&gt;
	&lt;li&gt;यद्यपि &amp;quot;रतौंधी&amp;quot; शब्द का अर्थ है कि आप रात में नहीं देख सकते हैं, यहाँ&amp;nbsp;ऐसा नहीं है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;विटामिन C&lt;/strong&gt; (एस्कॉर्बिक अम्ल) की कमी से &lt;strong&gt;स्कर्वी&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विटामिन D&lt;/strong&gt; (कैल्सीफेरॉल) की कमी से &lt;strong&gt;रिकेट्स&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विटामिन B7&lt;/strong&gt; (बायोटिन) की कमी से &lt;strong&gt;बाल झड़ते&lt;/strong&gt; हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;Let the mass of the earth be M.&lt;/li&gt;
	&lt;li&gt;Mass of the other object on earth is&amp;nbsp;m.&lt;/li&gt;
	&lt;li&gt;We know the value of Gravitational Constant (G) = 6.67259 &amp;times; 10&lt;sup&gt;-11&lt;/sup&gt; Nm&lt;sup&gt;2&lt;/sup&gt;/kg&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
	&lt;li&gt;We know the formula for the force between two objects (F) = G m&lt;sup&gt;1&lt;/sup&gt; m&lt;sup&gt;2&lt;/sup&gt;/r&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
	&lt;li&gt;Now the radius of the earth (r) = 6.3781 &amp;times; 10&lt;sup&gt;6&lt;/sup&gt; m.&lt;/li&gt;
	&lt;li&gt;We know that F = mg&lt;/li&gt;
	&lt;li&gt;Now by substituting the values, we get mg = G M m/r&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;M = g r&lt;sup&gt;2&lt;/sup&gt;/G&lt;/p&gt;

&lt;p&gt;M = (9.81) (6.3781 &amp;times; 10&lt;sup&gt;6&lt;/sup&gt;)&lt;sup&gt;2&lt;/sup&gt;/6.67259 &amp;times; 10&lt;sup&gt;-11&lt;/sup&gt;&lt;/p&gt;

&lt;p&gt;M = 6 &amp;times; 10&lt;sup&gt;24&lt;/sup&gt; kg.&lt;/p&gt;
The mass of the earth (M) is 6 &amp;times; 10&lt;sup&gt;24&lt;/sup&gt; kg.<br><br>&lt;ul&gt;
	&lt;li&gt;मान लीजिए कि पृथ्वी का द्रव्यमान M है।&lt;/li&gt;
	&lt;li&gt;पृथ्वी पर दूसरी वस्तु का द्रव्यमान m है।&lt;/li&gt;
	&lt;li&gt;हम गुरुत्वाकर्षण स्थिरांक (G) का मूल्य जानते हैं = 6.67259 &amp;times; 10&lt;sup&gt;-11&lt;/sup&gt; Nm&lt;sup&gt;2&lt;/sup&gt;/kg&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
	&lt;li&gt;हम दो वस्तुओं&amp;nbsp;के बीच बल के सूत्र को जानते हैं,&amp;nbsp;(F) = G m&lt;sup&gt;1&lt;/sup&gt; m&lt;sup&gt;2&lt;/sup&gt;/r&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
	&lt;li&gt;अब पृथ्वी की त्रिज्या (r) = 6.3781 &amp;times; 10&lt;sup&gt;6&lt;/sup&gt; m.&lt;/li&gt;
	&lt;li&gt;हम जानते हैं कि F = mg&lt;/li&gt;
	&lt;li&gt;अब मानों को प्रतिस्थापित करने पर&amp;nbsp;mg = G M m/r&lt;sup&gt;2&lt;/sup&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;M = g r&lt;sup&gt;2&lt;/sup&gt;/G&lt;/p&gt;

&lt;p&gt;M = (9.81) (6.3781 &amp;times; 10&lt;sup&gt;6&lt;/sup&gt;)&lt;sup&gt;2&lt;/sup&gt;/6.67259 &amp;times; 10&lt;sup&gt;-11&lt;/sup&gt;&lt;/p&gt;

&lt;p&gt;M = 6 &amp;times; 10&lt;sup&gt;24&lt;/sup&gt;&amp;nbsp;किलोग्राम&lt;/p&gt;
पृथ्वी का द्रव्यमान (M) is 6 &amp;times; 10&lt;sup&gt;24&lt;/sup&gt; किलोग्राम

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;2 kJ.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;CONCEPT&lt;/strong&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Potential energy&lt;/strong&gt;: The energy of any object due to its position with respect to a reference point is called potential energy. It is denoted by PE.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Potential energy is given by:&lt;/p&gt;

&lt;p&gt;PE&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;= m g h&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;Here, PE&amp;nbsp;is the&amp;nbsp;Potential Energy, m is the mass, g is the acceleration due to gravity, and h is the height at which the object is placed&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;CALCULATION&lt;/strong&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;p&gt;Given that:&amp;nbsp;&lt;/p&gt;

&lt;p&gt;Mass (m) = 10 Kg&lt;/p&gt;

&lt;p&gt;Height (h) = 20 m&lt;/p&gt;

&lt;p&gt;P.E.&amp;nbsp;= 10&amp;nbsp;x 10&amp;nbsp;x 20&lt;/p&gt;

&lt;p&gt;P.E.= 2000 J&lt;/p&gt;

&lt;p&gt;&amp;nbsp;P.E.&amp;nbsp;= &lt;strong&gt;2 kJ&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/05/Physics%20FT%204_Group%20X_jitendra_D1.PNG&quot; style=&quot;width: 141px; height: 44px;&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Kinetic energy: &lt;/strong&gt;The energy due to the motion of the object is called kinetic energy.&amp;nbsp;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Kinetic energy (KE) = 1/2 (mv&lt;sup&gt;2&lt;/sup&gt;)&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Where m is mass and v is velocity.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;Since the &lt;strong&gt;object is stationary (at rest) so the velocity is zero. Hence the kinetic energy of the object will be zero&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Only the potential energy of the object will be there at the height.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;2 kJ है।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;अवधारणा&lt;/strong&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37); &quot;&gt;स्थितिज&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;ऊर्जा&lt;/strong&gt;: संदर्भ बिंदु के संबंध में अपनी स्थिति के कारण किसी भी वस्तु की ऊर्जा को &lt;span style=&quot;color: rgb(37, 37, 37); &quot;&gt;स्थितिज&amp;nbsp;&lt;/span&gt;ऊर्जा कहा जाता है। इसे PE द्वारा निरूपित किया जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(37, 37, 37);&quot;&gt;स्थितिज&amp;nbsp;&lt;/span&gt;ऊर्जा इसके द्वारा दी गई है:&lt;/p&gt;

&lt;p&gt;PE&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;= m g h&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;यहाँ, PE &lt;span style=&quot;color: rgb(37, 37, 37);&quot;&gt;स्थितिज&amp;nbsp;&lt;/span&gt;ऊर्जा है, m द्रव्यमान है, g गुरुत्वाकर्षण के कारण त्वरण है&amp;nbsp;और h वह ऊँचाई है जिस पर वस्तु रखी जाती है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;गणना&lt;/strong&gt;&lt;/u&gt; :&lt;/p&gt;

&lt;p&gt;दिया गया है कि:&lt;/p&gt;

&lt;p&gt;द्रव्यमान&amp;nbsp;(m) = 10 Kg&lt;/p&gt;

&lt;p&gt;ऊंचाई (h) = 20 m&lt;/p&gt;

&lt;p&gt;P.E.&amp;nbsp;= 10&amp;nbsp;x 10&amp;nbsp;x 20&lt;/p&gt;

&lt;p&gt;P.E.= 2000 J&lt;/p&gt;

&lt;p&gt;P.E.&amp;nbsp;=&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;2 kJ&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/05/Physics%20FT%204_Group%20X_jitendra_D1.PNG&quot; style=&quot;width: 141px; height: 44px;&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गतिज ऊर्जा:&lt;/strong&gt; वस्तु की गति के कारण होने वाली ऊर्जा को गतिज ऊर्जा कहा जाता है।

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;गतिज ऊर्जा &lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(KE) = 1/2 (mv&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;जहाँ m द्रव्यमान है और v वेग है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;चूँकि &lt;strong&gt;वस्तु स्थिर (विरामावस्था पर) है, इसलिए वेग शून्य है। अतः वस्तु की गतिज ऊर्जा शून्य होगी&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;ऊंचाई पर&amp;nbsp;वस्तु की केवल &lt;span style=&quot;color: rgb(37, 37, 37);&quot;&gt;स्थितिज&amp;nbsp;&lt;/span&gt;ऊर्जा होगी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;There are two laws of chemical combination:&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Law of conservation of mass &lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;Law of conservation of mass states that in a chemical reaction mass can neither be created nor destroyed.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Law of constant proportion &lt;/strong&gt;&lt;/p&gt;
In a chemical substance the elements are always present in definite proportions by mass.<br><br>&lt;p&gt;रासायनिक संयोजन के दो नियम हैं:&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;द्रव्यमान के संरक्षण का नियम &lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;द्रव्यमान के संरक्षण का नियम बताता है कि रासायनिक अभिक्रिया में द्रव्यमान को ना तो निर्मित और ना ही नष्ट किया जा सकता है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;स्थिर अनुपात का नियम &lt;/strong&gt;&lt;/p&gt;
एक रासायनिक पदार्थ में तत्व सदैव द्रव्यमान द्वारा निश्चित अनुपात में मौजूद होते हैं।

&lt;p&gt;The correct answer is&lt;strong&gt; &lt;u&gt;Secretion of enzymes&lt;/u&gt;.&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-size:18px;&quot;&gt;&lt;u&gt;&lt;strong&gt;Key points&lt;/strong&gt;&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;It is an organic compound composed of&amp;nbsp;&lt;strong&gt;phosphate groups, adenine, and sugar ribose.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;These molecules provide energy for various&lt;strong&gt; biochemical processes in the body.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;Therefore, it is called the &amp;ldquo;&lt;strong&gt;Energy Currency of the Cell&amp;rdquo;. &lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;These ATP molecules are &lt;strong&gt;synthesized by Mitochondria,&lt;/strong&gt; therefore it is called the powerhouse of the cell.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;ATP is used for various&lt;strong&gt; cellular functions, including the transportation of different molecules across cell membranes.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;Other functions of ATP include supplying the energy required for&amp;nbsp;&lt;strong&gt;muscle contraction, circulation of blood, locomotion, nerve impulse propagation, Protein synthesis&amp;nbsp;and various body movements.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;The three phosphate groups present in this ATP molecule are called high-energy bonds as they are involved in the liberation of a huge amount of energy when they are broken. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;This molecule &lt;strong&gt;provides energy for various life processes &lt;/strong&gt;without which life cannot exist.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;&lt;u&gt;एंजाइमों का स्राव&lt;/u&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;यह एक कार्बनिक यौगिक है जो &lt;strong&gt;फॉस्फेट समूहों, एडेनीन और &lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;शर्करा&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;&lt;strong&gt;राइबोज&amp;nbsp;से बना है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;ये अणु &lt;strong&gt;शरीर में विभिन्न जैव रासायनिक अभिक्रियाओं के लिए ऊर्जा प्रदान करते हैं।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;अतः इसे &amp;quot;&lt;strong&gt;कोशिका की ऊर्जा मुद्रा&amp;quot; &lt;/strong&gt;&lt;/span&gt;कहा जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;इन एटीपी अणुओं का &lt;strong&gt;संश्लेषण माइटोकॉन्ड्रिया द्वारा किया जाता है,&lt;/strong&gt; इसलिए इसे कोशिका का बिजलीघर कहा जाता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;एटीपी का उपयोग विभिन्न &lt;strong&gt;कोशिकीय कार्यों के लिए किया जाता है, जिसमें कोशिका झिल्लियों में विभिन्न अणुओं का परिवहन शामिल है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;एटीपी के अन्य कार्यों में &lt;strong&gt;मांसपेशियों के संकुचन, रक्त के संचलन, &lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;चलन&lt;/strong&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;&lt;strong&gt;, तंत्रिका आवेग प्रसार, प्रोटीन संश्लेषण और शरीर की विभिन्न गतियों के लिए आवश्यक ऊर्जा की आपूर्ति शामिल है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;इस एटीपी अणु में मौजूद तीन फॉस्फेट समूहों को उच्च-ऊर्जा आबंध कहा जाता है क्योंकि वे टूटने पर बड़ी मात्रा में ऊर्जा की मुक्ति करते हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;यह अणु &lt;strong&gt;विभिन्न जीवन &lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;अभिक्रियाओं&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); &quot;&gt;&lt;strong&gt;के लिए ऊर्जा प्रदान करता है&lt;/strong&gt; जिसके बिना जीवन का अस्तित्व नहीं हो सकता।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;The number of water molecules that combine chemically in definite molecular proportion, with the concerned salt in the crystalline state is known as the &lt;strong&gt;water of crystallization.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Baking soda does NOT possess water of crystallization while other three do so.&lt;/li&gt;
&lt;/ul&gt;

