	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 115px; height: 20px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;दृष्टि का दोष&lt;/span&gt;&lt;/p&gt;
